1481	fn build_aggregate(
1482	    op: &AggOp,
1483	    target_name: &str,
1484	    on: &AggJoin,
1485	    filter: &Expr,
1486	    query: EvalTable<'_>,
1487	    snapshot: &Snapshot<'_>,
1488	    params: &ParamEnv,
1489	    cache: &mut AggCache<'_, '_>,
1490	) -> Result<Accumulator, EvalError> {
1491	    let target = query.target(target_name)?;
1492	    let target_fk = find_attr(&target.schema().attrs, &on.fk_attr)?;
1493	    let AttrType::Ref { table: group_table } = &target_fk.ty else {
1494	        return Err(EvalError::new("aggregate target join is not Ref-typed"));
1495	    };
1496	    let group_count = snapshot.row_count(query.box_name(), group_table)?;
1497	    let filter = eval_expr(
1498	        filter,
1499	        target,
1500	        &target.schema().attrs,
1501	        snapshot,
1502	        params,
1503	        cache,
1504	        Some(&RuntimeType::Bool),
1505	    )?;
1506	    let InternalColumn::Bool(filter) = filter else {
1507	        return Err(EvalError::new("aggregate filter did not evaluate to Bool"));
1508	    };
1509	
1510	    match op {
1511	        AggOp::Count => {
1512	            let mut groups = vec![0_i64; group_count];
1513	            for (row, include) in filter.iter().copied().enumerate() {
1514	                if include {
1515	                    let group = snapshot.reference(
1516	                        target.box_name(),
1517	                        target.table_name(),
1518	                        &on.fk_attr,
1519	                        row,
1520	                    )? as usize;
1521	                    groups[group] = groups[group].checked_add(1).ok_or_else(|| {
1522	                        EvalError::new(format!("aggregate Count overflow in group {group}"))
1523	                    })?;
1524	                }
1525	            }
1526	            Ok(Accumulator::Int(groups))
1527	        }
1528	        AggOp::Sum { value } => {
1529	            let values = eval_expr(
1530	                value,
1531	                target,
1532	                &target.schema().attrs,
1533	                snapshot,
1534	                params,
1535	                cache,
1536	                None,
1537	            )?;
1538	            match values {
1539	                InternalColumn::Int(values) => {
1540	                    let mut groups = vec![0_i64; group_count];
1541	                    for (row, (include, value)) in filter.iter().copied().zip(values).enumerate() {
1542	                        if include {
1543	                            let group = snapshot.reference(
1544	                                target.box_name(),
1545	                                target.table_name(),
1546	                                &on.fk_attr,
1547	                                row,
1548	                            )? as usize;
1549	                            groups[group] = groups[group].checked_add(value).ok_or_else(|| {
1550	                                EvalError::new(format!("integer Sum overflow in group {group}"))
1551	                            })?;
1552	                        }
1553	                    }
1554	                    Ok(Accumulator::Int(groups))
1555	                }
1556	                InternalColumn::Real(values) => {
1557	                    let mut groups = vec![0.0_f64; group_count];
1558	                    // This ascending target-row pass is the canonical CPU reduction order.
1559	                    for (row, (include, value)) in filter.iter().copied().zip(values).enumerate() {
1560	                        if include {
1561	                            let group = snapshot.reference(
1562	                                target.box_name(),
1563	                                target.table_name(),
1564	                                &on.fk_attr,
1565	                                row,
1566	                            )? as usize;
1567	                            groups[group] += value;
1568	                        }
1569	                    }
1570	                    Ok(Accumulator::Real(groups))
1571	                }
1572	                _ => Err(EvalError::new("Sum value did not evaluate to numeric")),
1573	            }
1574	        }
1575	    }
1576	}
