  3	/// CUDA capability facts used to make backend selection explicit and testable.
  4	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
  5	pub struct CudaAvailability {
  6	    pub driver_library: bool,
  7	    pub device_count: usize,
  8	    pub nvrtc_library: bool,
  9	}
 10	
 11	impl CudaAvailability {
 12	    /// Requires the one production CUDA path. This function never substitutes
 13	    /// the CPU oracle or any other backend.
 14	    pub fn require(self) -> Result<(), CudaError> {
 15	        if !self.driver_library {
 16	            return Err(CudaError::DriverMissing);
 17	        }
 18	        if self.device_count == 0 {
 19	            return Err(CudaError::NoDevice);
 20	        }
 21	        if !self.nvrtc_library {
 22	            return Err(CudaError::ToolkitMissing);
 23	        }
 24	        Ok(())
 25	    }
 26	}
